class TestDetectFormat:
    def test_detects_23andme(self):
        lines = SAMPLE_23ANDME.split("\n")[:10]
        assert detect_format(lines) == "23andme"

    def test_detects_ancestrydna(self):
        lines = SAMPLE_ANCESTRYDNA.split("\n")[:10]
        assert detect_format(lines) == "ancestrydna"

    def test_detects_vcf(self):
        lines = SAMPLE_VCF.split("\n")[:10]
        assert detect_format(lines) == "vcf"

    def test_detects_cgi(self):
        lines = SAMPLE_CGI.split("\n")[:10]
        assert detect_format(lines) == "cgi"

    def test_raises_on_unknown(self):
        with pytest.raises(ParseError):
            detect_format(["some random text", "with no structure"])


# ---------------------------------------------------------------------------
# 23andMe parser
