class TestParse23andMe:
    def test_basic_parsing(self):
        df = parse_23andme(SAMPLE_23ANDME)
        assert len(df) == 6
        assert df.columns == ["rsid", "chrom", "position", "allele1", "allele2"]

    def test_specific_variant(self):
        df = parse_23andme(SAMPLE_23ANDME)
        row = df.filter(pl.col("rsid") == "rs3094315")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "G"
        assert row["chrom"][0] == "1"
        assert row["position"][0] == 752566

    def test_homozygous(self):
        df = parse_23andme(SAMPLE_23ANDME)
        row = df.filter(pl.col("rsid") == "rs4477212")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "A"

    def test_filters_nocalls(self):
        df = parse_23andme(SAMPLE_23ANDME_WITH_NOCALLS)
        assert len(df) == 2
        rsids = df["rsid"].to_list()
        assert "rs4477212" in rsids
        assert "rs3094315" in rsids

    def test_haploid_genotype(self):
        df = parse_23andme(SAMPLE_23ANDME_HAPLOID)
        assert len(df) == 2
        row = df.filter(pl.col("rsid") == "rs4477212")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "A"

    def test_empty_file_raises(self):
        with pytest.raises(ParseError):
            parse_23andme("# comment only\n")

    def test_dtypes(self):
        df = parse_23andme(SAMPLE_23ANDME)
        assert df.schema["rsid"] == pl.Utf8
        assert df.schema["chrom"] == pl.Utf8
        assert df.schema["position"] == pl.Int64
        assert df.schema["allele1"] == pl.Utf8
        assert df.schema["allele2"] == pl.Utf8


