class TestParseVCF:
    def test_basic_parsing(self):
        df = parse_vcf(SAMPLE_VCF)
        assert len(df) == 3

    def test_homref_filtered(self):
        """Hom-ref (0/0) variants are dropped — they carry no information."""
        vcf = """\
##fileformat=VCFv4.1
#CHROM\tPOS\tID\tREF\tALT\tQUAL\tFILTER\tINFO\tFORMAT\tSAMPLE1
1\t100\trs100\tA\tG\t.\tPASS\t.\tGT\t0/0
1\t200\trs200\tC\tT\t.\tPASS\t.\tGT\t0/1
"""
        df = parse_vcf(vcf)
        assert len(df) == 1
        assert df["rsid"][0] == "rs200"

    def test_het(self):
        df = parse_vcf(SAMPLE_VCF)
        row = df.filter(pl.col("rsid") == "rs3094315")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "G"

    def test_homalt(self):
        df = parse_vcf(SAMPLE_VCF)
        row = df.filter(pl.col("rsid") == "rs3131972")
        assert row["allele1"][0] == "G"
        assert row["allele2"][0] == "G"

    def test_phased_genotype(self):
        df = parse_vcf(SAMPLE_VCF_PHASED)
        assert len(df) == 1
        row = df.row(0, named=True)
        assert row["allele1"] == "A"
        assert row["allele2"] == "G"
        # chr prefix should be stripped
        assert row["chrom"] == "1"

    def test_skips_multiallelic(self):
        df = parse_vcf(SAMPLE_VCF_MULTIALLELIC)
        assert len(df) == 1
        assert df["rsid"][0] == "rs3094315"

    def test_haploid_hemizygous_alt(self):
        """Hemizygous ALT on chrX (e.g. rs6323 MAOA in males) should be duplicated."""
        df = parse_vcf(SAMPLE_VCF_HAPLOID)
        row = df.filter(pl.col("rsid") == "rs6323")
        assert len(row) == 1
        assert row["allele1"][0] == "T"
        assert row["allele2"][0] == "T"
        assert row["chrom"][0] == "X"

    def test_haploid_hemizygous_ref_filtered(self):
        """Hemizygous REF on chrX (haploid 0 → 0/0) is filtered as hom-ref."""
        df = parse_vcf(SAMPLE_VCF_HAPLOID)
        row = df.filter(pl.col("rsid") == "rs99999")
        assert len(row) == 0

    def test_haploid_mixed_with_diploid(self):
        """Haploid and diploid calls in same VCF should both be parsed (hom-ref filtered)."""
        df = parse_vcf(SAMPLE_VCF_HAPLOID)
        assert len(df) == 2  # 1 haploid ALT + 1 diploid het (haploid REF filtered)

    def test_empty_file_raises(self):
        with pytest.raises(ParseError):
            parse_vcf("##fileformat=VCFv4.1\n#CHROM\tPOS\tID\n")


